import { Component, computed, inject, signal } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { Category } from '../../../core/models';

interface CategoryRow extends Category {
  /** Number of sources referencing this category — blocks delete (409) if > 0. */
  sourceCount: number;
}

@Component({
  selector: 'app-admin-categories',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './admin-categories.component.html',
  styleUrl: './admin-categories.component.css',
})
export class AdminCategoriesComponent {
  // inject() (not constructor params) so these are available to field initializers below.
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  // --- Backend-provided data (mock). ---
  categories = signal<CategoryRow[]>([
    { id: 'c1', name: 'Technology', slug: 'tech', articleCount: 128, sourceCount: 3 },
    { id: 'c2', name: 'World News', slug: 'world', articleCount: 156, sourceCount: 2 },
    { id: 'c3', name: 'Business', slug: 'business', articleCount: 94, sourceCount: 1 },
    { id: 'c4', name: 'Sports', slug: 'sports', articleCount: 41, sourceCount: 1 },
    { id: 'c5', name: 'Science', slug: 'science', articleCount: 63, sourceCount: 1 },
    { id: 'c6', name: 'Culture', slug: 'default', articleCount: 0, sourceCount: 0 },
  ]);

  private modalParam = toSignal(
    this.route.queryParams.pipe(map((p) => (p['modal'] as string) ?? null)),
    { initialValue: null },
  );
  showAddModal = computed(() => this.modalParam() === 'add-category');

  form = { name: '' };
  formError = signal<string | null>(null);
  submitting = signal(false);

  // Delete state + 409 surfacing
  pendingDeleteId = signal<string | null>(null);
  deleteError = signal<string | null>(null);

  openAdd(): void {
    this.formError.set(null);
    this.form = { name: '' };
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: 'add-category' },
      queryParamsHandling: 'merge',
    });
  }

  closeModal(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: null },
      queryParamsHandling: 'merge',
    });
  }

  submitAdd(): void {
    this.formError.set(null);
    const name = this.form.name.trim();
    if (!name) {
      this.formError.set('Category name is required.');
      return;
    }
    // Mimic unique-constraint 409.
    const dup = this.categories().some((c) => c.name.toLowerCase() === name.toLowerCase());
    if (dup) {
      this.formError.set(`409 — A category named “${name}” already exists.`);
      return;
    }

    this.submitting.set(true);
    setTimeout(() => {
      const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
      this.categories.update((list) => [
        ...list,
        { id: 'c' + (list.length + 1), name, slug: slug || 'default', articleCount: 0, sourceCount: 0 },
      ]);
      this.submitting.set(false);
      this.closeModal();
    }, 600);
  }

  askDelete(cat: CategoryRow): void {
    this.deleteError.set(null);
    if (cat.sourceCount > 0) {
      // Backend blocks delete with 409 when sources still reference the category.
      this.deleteError.set(
        `409 — “${cat.name}” is used by ${cat.sourceCount} source(s). Reassign or remove them first.`,
      );
      this.pendingDeleteId.set(null);
      return;
    }
    this.pendingDeleteId.set(cat.id);
  }
  cancelDelete(): void {
    this.pendingDeleteId.set(null);
  }
  confirmDelete(id: string): void {
    this.categories.update((list) => list.filter((c) => c.id !== id));
    this.pendingDeleteId.set(null);
  }

  catClass(slug: string): string {
    const known = ['tech', 'sports', 'world', 'business', 'science'];
    return known.includes(slug) ? `cat-${slug}` : 'cat-default';
  }
}
